for (const item of $input.all()) {
  // 1. Parse the stringified trades from Google Sheets into a real JSON object
  const trades = JSON.parse(item.json.Trades_Made);
  item.json.trades_parsed = trades;

  // 2. Extract just the ticker symbols (e.g., "AAPL,NVDA") for our News API
  const tickers = trades.map(trade => trade.ticker).join(',');
  item.json.tickers_list = tickers;
}
return $input.all();

